import{_ as e,o as t,c as i,a2 as o}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"账户常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/account-faq.md","filePath":"zh-CN/account/account-faq.md"}'),l={name:"account/account-faq.md"};function r(n,a,c,h,s,d){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="账户常见问题" tabindex="-1">账户常见问题 <a class="header-anchor" href="#账户常见问题" aria-label="Permalink to &quot;账户常见问题&quot;">​</a></h1><p>二步验证、短信验证码接收、休眠账户定义及激活方法。</p><h2 id="什么是二步验证" tabindex="-1">什么是二步验证 <a class="header-anchor" href="#什么是二步验证" aria-label="Permalink to &quot;什么是二步验证&quot;">​</a></h2><p>当进行交易、查看账户信息等与资产相关的操作时，需要输入交易密码。二步验证功能启用后，在校验完交易密码后，App 会通过安全验证或手机验证码进一步确认身份。</p><p>建议启用二步验证功能以保护账户安全。</p><h2 id="收不到短信验证码怎么办" tabindex="-1">收不到短信验证码怎么办 <a class="header-anchor" href="#收不到短信验证码怎么办" aria-label="Permalink to &quot;收不到短信验证码怎么办&quot;">​</a></h2><p>常见原因包括：短信被手机拦截、网络异常、收件箱已满。详细排查步骤参见<a href="/wiki/troubleshooting/收不到短信验证码">收不到短信验证码</a>。</p><h2 id="什么是休眠账户" tabindex="-1">什么是休眠账户 <a class="header-anchor" href="#什么是休眠账户" aria-label="Permalink to &quot;什么是休眠账户&quot;">​</a></h2><p>休眠账户是指长期未发生交易活动的账户。需同时满足以下条件：</p><ul><li>账户近 3 年无任何主动操作记录（包括证券交易、新股申购、基金认购、资金存入/提取、股票存入/提取等）</li><li>账户资产净值低于等值 100 港币</li></ul><p>休眠账户将暂停交易、出金及股票转出功能。如需重新激活，请通过以下方式联系长桥客服办理：</p><ul><li>在线客服</li><li>客服热线</li><li>客服邮箱</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/getting-started/first-deposit">完成首次入金</a> — 账户开通后完成第一笔存款的步骤</li><li><a href="/wiki/deposit/how-to-choose-deposit-method">如何选择入金方式</a> — 根据账户类型和需求选择入金方式</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/account">开户与账户</a></li></ul>',17)])])}const f=e(l,[["render",r]]);export{p as __pageData,f as default};
